    g(void 0, null, function* () {
      let i = [];
      yield h(t);
      for (let [o, r] of j)
        i.push({
          name: o,
          description: `${o} target`,
          icon: T.includes(o)
            ? "fig://icon?type=command"
            : "fig://icon?type=asterisk",
          args: { name: "project", suggestions: r.map((s) => ({ name: s })) },
          options: A.includes(o)
            ? [e.configuration, e.help, e.version]
            : [e.help, e.version],
        });
      return { name: "nx", subcommands: i };
    })

generators.script:
_NuFrRa_(n) => {
        let t = n.slice(-1)[0];
        return t.indexOf(":") > -1
          ? ["nx", "list", t.split(":")[0]]
          : ["nx", "list"];
      }

generators.postProcess:
_NuFrRa_(n) => {
        if (n.indexOf("Installed plugins") > -1) {
          let t = n.split(">"),
            i = t[1]
              .split(
                `
`
              )
              .filter(Boolean);
          i.shift();
          let o = t[2]
            .split(
              `
`
            )
            .filter(Boolean);
          return (
            o.shift(),
            [...i, ...o].map((r) => {
              let s = r.trim().split(" ")[0];
              return { name: s, insertValue: `${s}:` };
            })
          );
        } else if (n.indexOf("Capabilities") > -1)
          return n
            .split(
              `
`
            )
            .filter((i) => i.trim().indexOf(" : ") > -1)
            .map((i) => ({ name: i.trim().split(" : ")[0] }));
      }

